// triggerLabelText returns the text for the trigger button.
func triggerLabelText(cfg Config, state State) string {
	switch {
	case len(state.Selected) == 0:
		if cfg.Placeholder != "" {
			return cfg.Placeholder
		}
		return "Select…"
	case cfg.Mode == ModeSingle:
		for _, opt := range state.Options {
			if opt.Value == state.Selected[0] {
				return opt.Label
			}
		}
		return state.Selected[0]
	case len(state.Selected) == 1:
		for _, opt := range state.Options {
			if opt.Value == state.Selected[0] {
				return opt.Label
			}
		}
		return state.Selected[0]
	default:
		return strconv.Itoa(len(state.Selected)) + " selected"
	}
}

